#include<bits/stdc++.h>
using namespace std;
int b[200005],c[200005],value[200005];
bool cmp(int a,int b){
	return a>b;
}
int main()
{
	int n;
	cin>>n;
	long long ans=0;
	for(int i=0;i<2*n;i++){
		cin>>b[i];
		ans+=b[i];
	}
	for(int i=0;i<2*n;i++){
		cin>>c[i];
		value[i]=c[i]-b[i];
	}
	sort(value,value+2*n,cmp);
//	for(int i=0;i<2*n;i++){
//		cout<<value[i]<<' ';
//	}
	for(int i=0;i<n;i++){
		ans+=value[i];
	}
	cout<<ans;
}
